/**
 * Injects a "duplicate chapter" action into each book TOC row in edit mode.
 *
 * @module     booktool_duplicate/inject
 * @copyright  2026 Massey University
 * @license    http://www.gnu.org/copyleft/gpl.html GNU GPL v3 or later
 */
define("booktool_duplicate/inject",[],(function(){function g(u,n){if(!u){return null;}var q=u.indexOf("?");if(q===-1){return null;}var p=u.substring(q+1).split("&");for(var i=0;i<p.length;i++){var k=p[i].split("=");if(decodeURIComponent(k[0])===n){return decodeURIComponent(k[1]||"");}}return null;}function c(a){var l=a.querySelectorAll("a[href]");for(var i=0;i<l.length;i++){var h=l[i].getAttribute("href")||"";if(h.indexOf("delete.php")!==-1||h.indexOf("move.php")!==-1){var id=g(h,"chapterid");if(id){return id;}}}return null;}function b(h,l,u){var a=document.createElement("a");a.setAttribute("href",h);a.setAttribute("title",l);a.className="booktool_duplicate-action";var m=document.createElement("img");m.setAttribute("src",u);m.setAttribute("alt",l);m.className="icon";m.setAttribute("aria-hidden","false");a.appendChild(m);return a;}return{init:function(cmid,sesskey,label,iconUrl){var run=function(){var lists=document.querySelectorAll(".book_toc .action-list");if(!lists.length){return;}for(var i=0;i<lists.length;i++){var list=lists[i];if(list.querySelector(".booktool_duplicate-action")){continue;}var chapterid=c(list);if(!chapterid){continue;}var href=M.cfg.wwwroot+"/mod/book/tool/duplicate/duplicate.php?id="+encodeURIComponent(cmid)+"&chapterid="+encodeURIComponent(chapterid)+"&sesskey="+encodeURIComponent(sesskey);list.appendChild(b(href,label,iconUrl));}};if(document.readyState==="loading"){document.addEventListener("DOMContentLoaded",run);}else{run();}}};}));
